// Normalise les items des deux flux RSS et garde les N plus recents.
// On construit un id stable a partir du lien ou du titre.
const MAX_ITEMS = 6;

function makeId(item) {
  const base = item.guid || item.link || item.title || JSON.stringify(item);
  let h = 0;
  for (let i = 0; i < base.length; i++) {
    h = (h * 31 + base.charCodeAt(i)) >>> 0;
  }
  return String(h);
}

function cleanText(s) {
  if (!s) return '';
  return String(s)
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const out = [];
for (const entry of $input.all()) {
  const j = entry.json || {};
  const title = cleanText(j.title);
  if (!title) continue;
  const link = j.link || j.guid || '';
  const contentRaw = j.contentSnippet || j.content || j.summary || j.description || '';
  const content = cleanText(contentRaw).slice(0, 800);
  out.push({
    json: {
      id: makeId(j),
      title,
      link,
      content,
      pubDate: j.isoDate || j.pubDate || ''
    }
  });
}

// Tri par date decroissante quand la date existe.
out.sort((a, b) => {
  const da = Date.parse(a.json.pubDate) || 0;
  const db = Date.parse(b.json.pubDate) || 0;
  return db - da;
});

return out.slice(0, MAX_ITEMS);

// Deduplication contre un fichier d'etat /data/seen.json.
// On lit les ids deja vus, on filtre, puis on enregistre les nouveaux ids.
const fs = require('fs');
const path = '/data/seen.json';

let seen = [];
try {
  if (fs.existsSync(path)) {
    seen = JSON.parse(fs.readFileSync(path, 'utf8'));
    if (!Array.isArray(seen)) seen = [];
  }
} catch (e) {
  seen = [];
}
const seenSet = new Set(seen);

const fresh = [];
const newIds = [];
for (const entry of $input.all()) {
  const id = entry.json.id;
  if (!seenSet.has(id)) {
    fresh.push(entry);
    newIds.push(id);
    seenSet.add(id);
  }
}

try {
  // On borne la taille du fichier d'etat.
  const merged = Array.from(seenSet).slice(-500);
  fs.writeFileSync(path, JSON.stringify(merged, null, 2));
} catch (e) {
  // Si l'ecriture echoue on continue quand meme avec les items frais.
}

return fresh;

