// Parse la reponse du LLM, extrait le JSON, et garde les champs de l'article.
function extractJson(text) {
  if (!text) return null;
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch (e) {
    return null;
  }
}

const items = $input.all();
const source = $('Deduplication').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const article = (source[i] && source[i].json) || {};
  let content = '';
  try {
    content = resp.choices[0].message.content;
  } catch (e) {
    content = '';
  }
  const parsed = extractJson(content) || {};
  const tag = parsed.tag || 'Autre';
  let pertinence = parseInt(parsed.pertinence, 10);
  if (isNaN(pertinence)) pertinence = 0;
  const resume = parsed.resume || '(resume indisponible)';

  out.push({
    json: {
      date: new Date().toISOString().slice(0, 10),
      title: article.title || '',
      link: article.link || '',
      tag,
      pertinence,
      resume
    }
  });
}

return out;

// Ecrit les resultats dans /data/veille.md et /data/veille.csv en mode ajout.
const fs = require('fs');

const mdPath = '/data/veille.md';
const csvPath = '/data/veille.csv';

function csvEscape(s) {
  const v = String(s == null ? '' : s);
  if (v.includes('"') || v.includes(',') || v.includes('\n')) {
    return '"' + v.replace(/"/g, '""') + '"';
  }
  return v;
}

const rows = $input.all();

// En-tete Markdown si le fichier n'existe pas encore.
if (!fs.existsSync(mdPath)) {
  fs.writeFileSync(mdPath, '# Veille IA automatisee\n\nResultats produits par le workflow n8n.\n\n');
}
// En-tete CSV si le fichier n'existe pas encore.
if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, 'date,tag,pertinence,titre,lien,resume\n');
}

let mdBlock = '';
let csvBlock = '';
for (const r of rows) {
  const j = r.json;
  mdBlock += '## ' + j.title + '\n\n';
  mdBlock += '- Date: ' + j.date + '\n';
  mdBlock += '- Tag: ' + j.tag + '\n';
  mdBlock += '- Pertinence: ' + j.pertinence + '/5\n';
  if (j.link) mdBlock += '- Lien: ' + j.link + '\n';
  mdBlock += '\n' + j.resume + '\n\n';

  csvBlock += [
    csvEscape(j.date),
    csvEscape(j.tag),
    csvEscape(j.pertinence),
    csvEscape(j.title),
    csvEscape(j.link),
    csvEscape(j.resume)
  ].join(',') + '\n';
}

if (mdBlock) fs.appendFileSync(mdPath, mdBlock);
if (csvBlock) fs.appendFileSync(csvPath, csvBlock);

return [{ json: { ecrits: rows.length, md: mdPath, csv: csvPath } }];
